/*
 * Edexcel A-Level English Language (9EN0) — Exam Practice Question Bank
 * All written / exam-style questions. 20-40 per topic, mark scales 2-25.
 */

const ENGLISH_EDEXCEL_PRACTICE = {

  '1.1': {
    name: 'Individual and Social Variation',
    questions: [
      { q: 'Define "dialect" and "accent" with a one-sentence example of each.', marks: 2, markScheme: '• Dialect — language variety with distinctive lexis, grammar and often pronunciation, e.g. Geordie (1)\n• Accent — pronunciation pattern of a speaker or group, e.g. Cockney (1)' },
      { q: 'Define "idiolect" and "sociolect" with a one-sentence example of each.', marks: 2, markScheme: '• Idiolect — the unique linguistic profile of an individual, e.g. a writer\'s distinctive style (1)\n• Sociolect — a variety linked to a social group, e.g. teenage sociolect with specific slang (1)' },
      { q: 'State three sociolinguistic variables studied by Labov and Trudgill.', marks: 3, markScheme: '• Post-vocalic /r/ — Labov, New York (1)\n• /ing/ alternation ("walking" vs "walkin\'") — Trudgill, Norwich (1)\n• Plus (h) — Petyt, Bradford; (t) glottalisation in London — any third (1)' },
      { q: 'Describe Labov\'s New York department-store study and its main finding.', marks: 5, markScheme: '• Labov (1966) elicited /r/ production with "Where is the fourth floor?" (1)\n• Three stores: Saks (upper), Macy\'s (mid), S. Klein (lower) (1)\n• /r/ frequency increased with store prestige and careful speech (1)\n• Lower-middle-class Macy\'s staff hypercorrected — more /r/ than Saks in careful speech (1)\n• Established sociolinguistic variables correlate with social variables and formality (1)' },
      { q: 'Describe Trudgill\'s Norwich study and list three findings.', marks: 6, markScheme: '• Peter Trudgill (1974) studied five social classes on variables including -ing (1)\n• Finding 1: standard forms increased with class and formality (1)\n• Finding 2: women used more standard forms than men of the same class (1)\n• Finding 3: men over-reported non-standard use (covert prestige) (1)\n• Finding 4: women over-reported standard use (overt prestige) (1)\n• Conclusion: class, gender AND attitude shape variation (1)' },
      { q: 'Describe Milroy\'s Belfast study and explain the concept of network density.', marks: 5, markScheme: '• Lesley Milroy (1980) studied three working-class Belfast communities (1)\n• Measured network density (interconnectedness) + multiplexity (roles per contact) (1)\n• High-density networks correlated with higher use of local vernacular forms (1)\n• Looser networks (often women in the sample) showed more standard forms (1)\n• Concluded network strength — not class alone — predicts variation (1)' },
      { q: 'Define "overt prestige" and "covert prestige" and explain why both concepts matter.', marks: 4, markScheme: '• Overt — prestige attached to standard publicly-valued forms (1)\n• Covert — prestige attached to non-standard forms within a peer group (1)\n• Both operate in every speaker: overt drives convergence in formal contexts; covert drives retention of vernacular in peer contexts (1)\n• Ignoring either gives a partial picture (1)' },
      { q: 'Identify four typical features of Cockney English.', marks: 4, markScheme: '• H-dropping ("\'ouse") (1)\n• T-glottalisation ("be\'er" for "better") (1)\n• Th-fronting ("fink" for "think") (1)\n• Double negation; rhyming slang — any valid fourth (1)' },
      { q: 'Identify four features of Geordie (Tyneside) English.', marks: 4, markScheme: '• Distinctive vowel qualities (1)\n• Address terms e.g. "pet", "man", "marra" (1)\n• Lexis: "howay" (come on), "bairn" (child), "nowt" (nothing) (1)\n• Distinctive intonation contours (1)' },
      { q: 'Explain Howard Giles\'s Accommodation Theory and give two examples.', marks: 5, markScheme: '• Speakers adjust style in interaction (1)\n• Convergence — moving towards listener\'s style, usually to build rapport (1)\n• Divergence — moving away, often to assert identity or distance (1)\n• Example: British migrant adopting Australian vowels at work (convergence) (1)\n• Example: teenager thickening local accent with parents (maintenance / divergence) (1)' },
      { q: 'Describe Jenny Cheshire\'s Reading study of adolescent speech.', marks: 4, markScheme: '• Cheshire (1982) studied adolescents in Reading (1)\n• Found non-standard grammatical features (e.g. "we was", multiple negation) correlated with peer-group membership (1)\n• Non-standard features served as markers of toughness / covert prestige (1)\n• Showed variation is driven by identity construction, not class alone (1)' },
      { q: 'Describe K.M. Petyt\'s Bradford study and state its main finding.', marks: 3, markScheme: '• Petyt studied H-dropping in Bradford (1)\n• Found clear correlation with social class — more H-dropping in lower classes (1)\n• Confirmed class-based patterning of UK phonological variables (1)' },
      { q: 'Define "hypercorrection" (Labov) and give an example.', marks: 3, markScheme: '• Over-application of a prestige form beyond its normal contexts (1)\n• Example: "between you and I" (hypercorrecting "between you and me") (1)\n• Often observed in aspirant social groups overshooting the prestige norm (1)' },
      { q: 'Describe Paul Kerswill\'s work on dialect levelling.', marks: 4, markScheme: '• Kerswill studied new towns (e.g. Milton Keynes) and urban varieties (1)\n• Found that distinctive local features are reducing with mobility and media (1)\n• A more generalised South-Eastern variety emerges (1)\n• However NEW varieties (MLE) emerge too — levelling is not uniformity (1)' },
      { q: 'Define "community of practice" (Eckert &amp; McConnell-Ginet) and give one benefit over class-based analysis.', marks: 4, markScheme: '• A group cohering around shared practices and goals (1)\n• Members share linguistic repertoires (1)\n• Benefit: allows intersectional analysis (class, gender, ethnicity, age interact) (1)\n• Reflects the fluid, constructed nature of identity that static variables miss (1)' },
      { q: 'Describe Bernstein\'s "restricted" and "elaborated" codes and state one critique.', marks: 5, markScheme: '• Restricted code — context-bound, shared-assumption speech (1)\n• Elaborated code — explicit, decontextualised (1)\n• Bernstein argued schools reward elaborated code, potentially disadvantaging working-class pupils (1)\n• Critique: Labov\'s research on AAVE shows vernacular speakers command rule-governed systems — the "deficit" reading is unsupported (1)\n• Modern sociolinguistics prefers "code difference" to "code deficit" (1)' },
      { q: 'Analyse the following transcript for indicators of social identity:\nSpeaker (builder, West London, mid-30s): "Yeah nah we was down the yard an\' me mate goes \'ain\'t liftin\' that mate\' an\' I\'m like bruv."', marks: 8, markScheme: '• Non-standard preterite "we was" — vernacular (1)\n• "Me" as possessive — London vernacular (1)\n• "Ain\'t" — stigmatised non-standard negation with covert prestige (1)\n• Address "bruv", "mate" — peer solidarity (1)\n• Quotative "I\'m like" + "goes" — MLE/youth variant (1)\n• Overall: speech indexes working-class London identity, with MLE influence (1)\n• Apply Trudgill on covert prestige; Milroy on network density (1)\n• Avoid deficit framing — the variety is rule-governed (1)' },
      { q: 'Analyse how class, age and gender interact in the speech of a 22-year-old university student from London.', marks: 8, markScheme: '• Age + student status → likely MLE / youth vernacular features (1)\n• Class: converges towards standard forms in essays, interviews (1)\n• Gender: potentially more standard forms in formal contexts (Trudgill), but variable (1)\n• Network density: dense peer network in halls reinforces MLE; family network reinforces other varieties (1)\n• Accommodation: student style-shifts across contexts (1)\n• Covert prestige: MLE features retained in peer contexts (1)\n• Community of practice — overlapping identities drive flexible repertoire (1)\n• Avoid monolithic claims — many factors interact (1)' },
      { q: 'Discuss: "Social class remains the most important variable in UK sociolinguistics." Evaluate. [15 marks]', marks: 15, markScheme: '• Class historically central — Labov, Trudgill, Petyt found strong patterning (2 + 2)\n• But class alone cannot explain gender/age patterns, covert prestige, network effects (2 + 2)\n• Milroy showed network outperforms class in some contexts (2)\n• Eckert\'s community of practice challenges static categories (2)\n• MLE shows ethnic variation interacts with age and class (2)\n• Conclusion: class remains important but must combine with age, gender, network, ethnicity and identity — no longer paramount in isolation (1)' },
      { q: 'Analyse a distinctive speech feature of YOUR OWN regional area (or London if unfamiliar) and link to at least two theorists. [15 marks]', marks: 15, markScheme: '• Identify a specific feature (e.g. T-glottalisation in London) (2)\n• Describe phonetic realisation and distribution (2)\n• Link to social variables (age, class) — e.g. spreading upward from working-class (3)\n• Theorist 1: Labov/Trudgill on class and prestige patterns (3)\n• Theorist 2: Milroy on network effects, or Kerswill on levelling (3)\n• Evaluation: discuss identity functions (covert prestige), media influence, ongoing change (2)' },
    ],
  },

  '1.2': {
    name: 'Historical Language Change',
    questions: [
      { q: 'Outline the four historical periods of English with approximate dates.', marks: 4, markScheme: '• Old English (c. 450–1066) (1)\n• Middle English (1066–c. 1500) (1)\n• Early Modern English (c. 1500–1700) (1)\n• Modern English (1700–present) (1)' },
      { q: 'Identify four major influences on English lexis historically.', marks: 4, markScheme: '• Latin and Greek (1)\n• Norman French (1066+) (1)\n• Old Norse (1)\n• Modern contact — colonisation, globalisation, migration, technology (1)' },
      { q: 'Define broadening, narrowing, amelioration and pejoration with an example of each.', marks: 8, markScheme: '• Broadening — "dog" once a specific breed, now any canine (2)\n• Narrowing — "meat" once any food, now flesh (2)\n• Amelioration — "nice" once "foolish", now pleasant (2)\n• Pejoration — "silly" once "blessed", now foolish (2)' },
      { q: 'Name six word-formation processes with one example each.', marks: 6, markScheme: '• Affixation — "unhappiness" (1)\n• Compounding — "laptop" (1)\n• Blending — "brunch" (1)\n• Clipping — "exam" (1)\n• Acronym — "NATO" (1)\n• Eponym — "sandwich"; OR conversion "text"; OR borrowing "tsunami" (1)' },
      { q: 'Describe Aitchison\'s three metaphors and her overall argument.', marks: 6, markScheme: '• "Damp spoon" — change caused by laziness (2)\n• "Crumbling castle" — nostalgic decay narrative (2)\n• "Infectious disease" — spread as pathology (1)\n• Aitchison REJECTS all three; argues change is natural, systematic and functional (1)' },
      { q: 'Describe the S-curve and the wave theory of change.', marks: 6, markScheme: '• S-curve: slow innovator uptake → rapid spread → plateau (Labov) (3)\n• Wave theory: change spreads from an epicentre outward, weakening with distance (Samuels) (3)' },
      { q: 'Explain Halliday\'s functional view of language change.', marks: 3, markScheme: '• Language changes to meet users\' changing communicative needs (1)\n• New domains (technology, commerce, identity) produce new lexis/registers (1)\n• Functional motivation, not decay (1)' },
      { q: 'Describe two ways technology has driven recent lexical change, with examples.', marks: 4, markScheme: '• New lexis tied to digital practice: "doomscroll", "unfriend", "swipe" (2)\n• Conversion: "text" (noun → verb); "friend" (noun → verb on social media) (2)' },
      { q: 'Describe two historical influences that accelerated standardisation of English.', marks: 4, markScheme: '• Caxton\'s printing press (1476) spreading a written standard (2)\n• Johnson\'s Dictionary (1755) codifying spellings and definitions (2)' },
      { q: 'Explain why "literally" as an intensifier is not linguistically new.', marks: 4, markScheme: '• Semantic shift is continuous (1)\n• Figurative use of "literally" has 18th-century precedents (1)\n• Prescriptive complaints are style preferences, not linguistic facts (1)\n• Descriptivist framework (Crystal, Aitchison) accommodates such shifts as normal (1)' },
      { q: 'Describe singular "they" as an example of ongoing grammatical change.', marks: 4, markScheme: '• Attested since the 14th century (1)\n• 18th-century grammarians imposed "he" as generic (1)\n• Resurgence for gender-neutral and non-binary reference (1)\n• Recognised by major dictionaries and style guides — example of grammatical change meeting communicative need (1)' },
      { q: 'Analyse a short extract from a 17th-century text alongside a 21st-century equivalent. Identify three linguistic changes.', marks: 6, markScheme: '• Orthography — variable 17C spelling vs standardised 21C (1 + 1)\n• Grammar — loss of thou/thee; modal range; new conversion verbs (1 + 1)\n• Lexis — archaic vocabulary vs digital era terms (1 + 1)' },
      { q: 'Evaluate: "English is becoming simpler." Discuss using at least two examples.', marks: 8, markScheme: '• Simplification in some areas — loss of pronoun distinctions, reduced verb inflections (2)\n• Complexity gains — lexical expansion, new genres (2)\n• Written forms remain grammatically complex (1)\n• Contact varieties (MLE) add new complexity (1)\n• Conclusion: English transforms, not just simplifies (2)' },
      { q: 'Analyse how political correctness has reshaped everyday lexis in the last 40 years.', marks: 8, markScheme: '• Shift from "handicapped" → "disabled" → "person with a disability" (2)\n• Gender-inclusive "chairperson", "firefighter" (1)\n• Sensitivity around mental-health lexis ("deranged" → "experiencing mental illness") (1)\n• Cameron\'s "verbal hygiene" — change tracks shifting social values (2)\n• Debate: descriptive (Crystal) vs prescriptive reactions (Heffer, Humphrys) (2)' },
      { q: 'Discuss how globalisation has accelerated language change. [15 marks]', marks: 15, markScheme: '• Mobility + media accelerate diffusion (3)\n• Loanwords enter daily lexis (tsunami, barista, hijab) (3)\n• Pluricentric development (Crystal) (3)\n• Contact varieties emerge in cosmopolitan cities (3)\n• Levelling vs new varieties (3)' },
      { q: 'Analyse an invented 17th-century sentence: "Prithee, good mistresse, hie thee to yonder marketplace." Identify four features of Early Modern English.', marks: 6, markScheme: '• Archaic interjection "Prithee" (1)\n• Polite form "good mistresse" with archaic spelling (1)\n• Verb "hie" (to hurry) now archaic (1)\n• Reflexive construction "hie thee" + "thee" pronoun (1)\n• Deictic "yonder" (1)\n• Overall: lexis + grammar typical of EME (1)' },
      { q: 'Evaluate the view that prescriptivist concern about change is linguistically justified. [15 marks]', marks: 15, markScheme: '• Concern: change as decline (3)\n• Descriptivist response: change is natural (3)\n• Aitchison\'s metaphors as diagnostic of prescriptivist rhetoric (3)\n• Crystal: many "decline" examples have long precedents (3)\n• Cameron: concern reflects social anxiety, not linguistic fact (2)\n• Conclusion: concern is socially intelligible but linguistically unsupported (1)' },
      { q: 'Evaluate: "Contact with other languages is the main driver of English change." Discuss. [10 marks]', marks: 10, markScheme: '• Contact has driven major waves — French, Norse, Latin/Greek, colonisation, globalisation (3)\n• But internal change (grammatical simplification, semantic drift) also occurs (3)\n• Technology drives recent lexical innovation alongside contact (2)\n• Therefore contact is a major driver but one of several (2)' },
      { q: 'Describe two features of 21st-century English change that a linguist would highlight as significant.', marks: 6, markScheme: '• Use of singular "they" (1 + 1)\n• Rapid adoption of digital lexis (swipe, ghost, unfriend) via social media (1 + 1)\n• Re-analysis of punctuation in digital chat (full stop as pragmatic marker) (1 + 1)' },
      { q: 'Write an analytical essay on how English is changing in the 2020s. Integrate at least three theorists. [20 marks]', marks: 20, markScheme: 'Up to 20. Indicative:\n• Intro: change is continuous (Halliday) (2)\n• Technology-driven change with examples (3)\n• Social change — pronouns, inclusive lexis (3)\n• Contact-driven change (MLE, new Englishes) (3)\n• Attitudes: Crystal, Aitchison, Cameron (3)\n• Prescriptivist counter-voices (3)\n• Evaluation (2)\n• Conclusion: English is diversifying, pluricentric, dynamic — not in decline (1)' },
    ],
  },

  '1.3': {
    name: 'Global and Regional Variation',
    questions: [
      { q: 'Name Kachru\'s three circles with two example countries for each.', marks: 6, markScheme: '• Inner — UK, US, Australia, Canada, NZ (any two, 2)\n• Outer — India, Nigeria, Singapore (any two, 2)\n• Expanding — China, Brazil, Russia, Japan (any two, 2)' },
      { q: 'State one limitation of Kachru\'s Three Circles model.', marks: 3, markScheme: '• Implies Inner-Circle hierarchy (1)\n• Many Expanding-Circle speakers are more proficient than some Inner-Circle speakers (1)\n• Categories blur — Indian English is pluricentric in its own right (1)' },
      { q: 'Define ELF and name a key theorist.', marks: 2, markScheme: '• English as a Lingua Franca — English used for communication between non-native speakers (1)\n• Jennifer Jenkins; Lingua Franca Core (1)' },
      { q: 'Describe four features of Multicultural London English.', marks: 8, markScheme: '• Fronted GOOSE vowel (2)\n• Lexis from Caribbean, South Asian, vernacular London sources (2)\n• Quotative "this is me"; new quotative system (2)\n• Use of "man" as indefinite pronoun (2)' },
      { q: 'Explain who studied MLE and what they found.', marks: 4, markScheme: '• Paul Kerswill and Jenny Cheshire (2011) (1)\n• Emerging distinctive variety in inner-London adolescent peer networks (1)\n• Features shared across ethnic lines — community-based (1)\n• Spreading beyond London as a youth variety (1)' },
      { q: 'Describe four features of AAVE.', marks: 8, markScheme: '• Habitual "be" — "she be working" (2)\n• Copula deletion — "she happy" (2)\n• Double negation (2)\n• Aspectual stressed "been" + consonant cluster reduction (2)' },
      { q: 'Explain Labov\'s contribution to AAVE research.', marks: 4, markScheme: '• Labov (1972) studied AAVE in Harlem (1)\n• Demonstrated AAVE is rule-governed (1)\n• Argued its stigmatisation is social, not linguistic (1)\n• Contributed to education debates (Ann Arbor decision 1979) (1)' },
      { q: 'Define pidgin and creole with a named example.', marks: 4, markScheme: '• Pidgin — simplified contact language, no native speakers (1)\n• Creole — pidgin acquired as a native language with expanded grammar (1)\n• Example: Jamaican Creole from Caribbean pidgins (1)\n• Shows rapid language emergence under contact (1)' },
      { q: 'Identify three features of Indian English.', marks: 3, markScheme: '• Distinctive lexis — "prepone", "out of station" (1)\n• Progressive with stative verbs ("I am understanding") (1)\n• Invariant tag "isn\'t it?" (1)' },
      { q: 'Define code-switching and code-mixing with an example of each.', marks: 4, markScheme: '• Code-switching — alternation across clauses/turns (2)\n• Code-mixing — mixing within a clause (e.g. a Hindi word inside an English sentence) (2)' },
      { q: 'Explain translanguaging with one example.', marks: 4, markScheme: '• Multilingual speakers draw on their full repertoire flexibly (1)\n• Rejects view of languages as bounded systems (1)\n• Educational implication: pedagogy that values all learner languages tends to improve outcomes (1)\n• Example: bilingual Spanish-English student using both in discussion (1)' },
      { q: 'Describe two features of Singlish and their sources.', marks: 4, markScheme: '• Final particles "lah", "lor", "meh" — attitudinal markers (2)\n• Topic-prominent syntax influenced by Malay/Chinese (2)' },
      { q: 'Analyse how media representations of MLE reflect an ideology.', marks: 6, markScheme: '• Labels "jafaican", "street slang" — pejorative (1)\n• Erase the fact that MLE is rule-governed (1)\n• Moral panic narratives about youth/crime (1)\n• Racialised standard-language ideology (1)\n• A classic case for Paper 3 (Language Discourses) analysis (1)\n• Reveal that public attitudes lag behind linguistic fact (1)' },
      { q: 'Explain the concept of a "lectal continuum".', marks: 3, markScheme: '• Basilect — furthest from standard (1)\n• Mesolect — intermediate (1)\n• Acrolect — closest to standard; speakers shift along the continuum by context (1)' },
      { q: 'Identify three factors that contribute to ethnolinguistic vitality (Giles).', marks: 3, markScheme: '• Demographic strength (1)\n• Institutional support (1)\n• Status / prestige (1)' },
      { q: 'Explain why the "native/non-native" distinction is increasingly problematic in ELF.', marks: 4, markScheme: '• Majority of English use is between non-native speakers (1)\n• Many ELF speakers are highly proficient (1)\n• "Native" confers unwarranted authority (Jenkins) (1)\n• "Expert user" is preferred (1)' },
      { q: 'Discuss: "English\'s global spread should be welcomed as a lingua franca." [15 marks]', marks: 15, markScheme: '• Pro: access, communication, economic opportunity (3)\n• Pro: pluricentrism — new Englishes with legitimate norms (3)\n• Con: language endangerment, linguistic inequality, colonial legacy (3)\n• Con: cognitive/cultural costs in education (3)\n• Balanced evaluation — spread is mixed (3)' },
      { q: 'Analyse the language of an invented Bollywood film extract for code-switching and world English features. Use at least two theorists. [12 marks]', marks: 12, markScheme: '• Identify features — lexis, grammar, phonology (3)\n• Code-switching functions — identity, audience design (3)\n• Theorist 1: Kachru (pluricentric English) (2)\n• Theorist 2: García (translanguaging) / Jenkins (ELF) (2)\n• Evaluate — challenges Inner-Circle norms (2)' },
      { q: 'Discuss how standard-language ideology has affected educational policy towards AAVE. [12 marks]', marks: 12, markScheme: '• Historical treatment as deficient (Bereiter & Engelmann) (2)\n• Labov\'s counter-argument; Ann Arbor (1979) (3)\n• Ebonics debate (1996) (3)\n• Current: code-switching pedagogy, contrastive analysis (2)\n• Ideology still shapes attitudes despite evidence (2)' },
      { q: 'Write a 600-word commentary on how English has produced "new Englishes". Use at least three theorists. [20 marks]', marks: 20, markScheme: 'Up to 20. Indicative:\n• Intro: English\'s spread via colonisation, globalisation (2)\n• Kachru\'s circles — strengths + limits (3)\n• Crystal on pluricentrism (3)\n• Jenkins on ELF/LFC (3)\n• Example 1: Indian English (3)\n• Example 2: Singlish (3)\n• Evaluation (2)\n• Conclusion: English is pluralised; analysis must engage pluricentric norms (2)' },
    ],
  },

  '2.1': {
    name: "Children's Spoken Language Development",
    questions: [
      { q: 'Name and describe the four main stages of spoken language development.', marks: 4, markScheme: '• Pre-verbal (0–12m): cooing, babbling (1)\n• Holophrastic (12–18m): single words (1)\n• Two-word (18–24m): "daddy gone" (1)\n• Telegraphic → post-telegraphic (2–5y) (1)' },
      { q: 'Describe Halliday\'s seven functions with examples.', marks: 7, markScheme: '• Instrumental — "want juice" (1)\n• Regulatory — "no bed" (1)\n• Interactional — "hi nanny" (1)\n• Personal — "me happy" (1)\n• Heuristic — "what\'s that?" (1)\n• Imaginative — "I\'m a dragon" (1)\n• Representational — "doggy barking" (1)' },
      { q: 'Explain what CDS is and list three typical features.', marks: 4, markScheme: '• Child-directed speech / motherese / parentese — register with infants (1)\n• Higher pitch + exaggerated intonation (1)\n• Slower pace + clearer articulation + repetition (1)\n• Simplified vocabulary + questions to invite turns (1)' },
      { q: 'State Skinner\'s behaviourist theory of acquisition and give one criticism.', marks: 4, markScheme: '• Imitation + reinforcement + conditioning (1 + 1)\n• Criticism: cannot explain virtuous errors (forms the child has never heard) (1)\n• Novel utterances are produced — suggests internal rules, not pure imitation (1)' },
      { q: 'Describe Chomsky\'s nativist theory and two pieces of evidence.', marks: 5, markScheme: '• Innate Language Acquisition Device + Universal Grammar (1)\n• Evidence: virtuous errors show rule-following (1)\n• Evidence: poverty of the stimulus — input is incomplete (1)\n• Evidence: critical period; universals across languages (1 + 1)' },
      { q: 'Describe Genie and the critical period hypothesis.', marks: 5, markScheme: '• Genie isolated until age 13 with no language (1)\n• Acquired lexis but never mastered complex grammar (1)\n• Supports Lenneberg\'s critical period (1)\n• Caveats: single case; trauma as confound (1)\n• Still widely cited as evidence (1)' },
      { q: 'Describe Bruner\'s LASS with a concrete example.', marks: 4, markScheme: '• Language Acquisition Support System — social scaffolding (1)\n• Joint attention — shared focus between caregiver and child (1)\n• Example: picture-book routine — point, name, pause, wait (1)\n• Complements Chomsky\'s LAD (1)' },
      { q: 'Explain Piaget\'s cognitive theory.', marks: 4, markScheme: '• Language development linked to cognitive development (1)\n• Children cannot use a concept before understanding it (1)\n• Example: consistent tense before grasping time (1)\n• Limitation: Vygotsky — language can drive cognition too (1)' },
      { q: 'Explain Vygotsky\'s ZPD applied to language.', marks: 4, markScheme: '• Gap between independent and with-guidance competence (1)\n• Caregiver models forms slightly beyond the child (1)\n• Scaffolding within ZPD accelerates development (1)\n• Internalisation as competence grows (1)' },
      { q: 'Using an example, explain what a virtuous error is and why it matters.', marks: 4, markScheme: '• Overgeneralisation of a regular rule (1)\n• Example: "mouses" / "goed" (1)\n• Shows rule-learning, not imitation (1)\n• Supports nativist / rule-based theories (1)' },
      { q: 'Describe Berko\'s wug test and its theoretical importance.', marks: 6, markScheme: '• Invent a novel creature "wug" (1)\n• Show a picture and elicit plural (1)\n• Children produce "wugs" — applying the plural rule (1)\n• Shows productive, rule-based knowledge (1)\n• Evidence for nativist / generative accounts (1)\n• Crucial for distinguishing imitation from rule-learning (1)' },
      { q: 'Describe two common features of early pronunciation errors.', marks: 4, markScheme: '• Consonant cluster reduction — "poon" for "spoon" (1)\n• Substitution — /w/ for /r/ (1)\n• Deletion of unstressed syllables — "nana" for "banana" (1)\n• Assimilation — "doggy" → "goggy" (1)' },
      { q: 'Analyse:\nChild (2.4): "Daddy gone shop."\nFather: "Yes, daddy\'s gone to the shop to get some milk."\nIdentify stage and scaffolding.', marks: 6, markScheme: '• Child: telegraphic stage — content words only (1)\n• Subject + past-participle + noun — correct word order (1)\n• Father recasts (providing adult form) (1)\n• Father expands semantically (adds "milk") (1)\n• Both are features of Bruner\'s LASS (1)\n• Supports interactionist view (1)' },
      { q: 'Explain two differences between Halliday\'s "instrumental" and "interactional" functions.', marks: 4, markScheme: '• Instrumental: getting what you need — goal-directed (1)\n• Interactional: social bonds — relational (1)\n• Both emerge early — pragmatic sophistication before grammatical maturity (1)\n• Instrumental often precedes complex grammar (1)' },
      { q: 'Describe two techniques observed in caregivers\' CDS.', marks: 4, markScheme: '• Recasting — repeating in correct form (1)\n• Expansion — adding information (1)\n• Exaggerated intonation and pauses to invite turns (1)\n• Reference to here-and-now via deictic pointing (1)' },
      { q: 'State two limitations of experimental studies of child language.', marks: 4, markScheme: '• Samples often small and culturally specific (1)\n• Experimental settings are not natural (1)\n• Ethical constraints limit duration / type (1)\n• Cannot directly observe mental representations (1)' },
      { q: 'A child aged 3 says: "Me eat biscuit because I hungry." Identify two features present and two not yet mastered.', marks: 8, markScheme: '• Present: subordinate clause with "because" — post-telegraphic (1 + 1)\n• Present: correct word order, tense (1 + 1)\n• Not yet: nominative "I" — uses "Me" (1 + 1)\n• Not yet: copula ellipsis — "I hungry" (missing "am") (1 + 1)' },
      { q: 'Compare Skinner and Bruner and evaluate which offers the stronger account.', marks: 10, markScheme: '• Skinner: behaviourism — imitation + reinforcement (2)\n• Weakness: cannot explain virtuous errors or novel utterances (1)\n• Bruner: LASS — scaffolded interaction (2)\n• Strength: explains input-quality variation (1)\n• Limit of Bruner alone: does not address internal mechanisms — Chomsky needed (1)\n• Most linguists adopt a combined nativist + interactionist view (1)\n• Conclusion: Bruner > Skinner, but combined with Chomsky is strongest (2)' },
      { q: 'Evaluate: "Child language acquisition is primarily social, not innate." [15 marks]', marks: 15, markScheme: '• Social (Bruner, Vygotsky) — Genie and Jim cases suggest input is essential (3)\n• Halliday\'s functional framework supports social (2)\n• Innate (Chomsky) — poverty of stimulus, Universal Grammar, critical period (3)\n• Virtuous errors show rule-learning (2)\n• Interactionist synthesis is best (3)\n• Therefore statement overstates the social — balanced evaluation required (2)' },
      { q: 'Analyse how a caregiver might scaffold a 2-year-old\'s language over a picture-book session. Integrate three theorists. [20 marks]', marks: 20, markScheme: 'Up to 20:\n• Joint attention (Bruner) (3)\n• Labelling supporting heuristic function (Halliday) (3)\n• ZPD-directed questions (Vygotsky) (3)\n• Recasting + expansion (CDS) (3)\n• Phatic through eye contact and affective pitch (2)\n• Piaget: concepts scaffolded via familiar characters (2)\n• Chomsky: innate capacity activated by comprehensible input (2)\n• Synthesis: picture-book interaction exemplifies nativist, interactionist and functional mechanisms together (2)' },
    ],
  },

  '2.2': {
    name: "Children's Written Language Development",
    questions: [
      { q: 'Name Kroll\'s four stages with age guidance.', marks: 4, markScheme: '• Preparation — up to age 6 (1)\n• Consolidation — around 7–8 (1)\n• Differentiation — around 9–10 (1)\n• Integration — teenage years onward (1)' },
      { q: 'Describe Kroll\'s consolidation stage with two typical features.', marks: 3, markScheme: '• Writing resembles speech (1)\n• Heavy coordination with "and"/"then" (1)\n• First-person perspective, limited punctuation (1)' },
      { q: 'State Britton\'s three functions with an example of each.', marks: 6, markScheme: '• Expressive — diary entry (2)\n• Transactional — letter to council (2)\n• Poetic — crafted story/poem (2)' },
      { q: 'Describe Rothery\'s four genre categories with a typical text type for each.', marks: 8, markScheme: '• Recount — holiday retelling (2)\n• Report — animal report (2)\n• Narrative — adventure story (2)\n• Observation/comment — nature-walk note (2)' },
      { q: 'Explain why a Year 3 writer\'s coordination-heavy style is developmentally typical, and how a teacher could scaffold.', marks: 5, markScheme: '• Kroll consolidation — writing reflects speech (1)\n• Child has not yet internalised range of connectors (1)\n• Teacher models complex sentences and introduces subordinators ("because", "although") (1)\n• Shared writing in ZPD jointly constructs complex prose (1)\n• Explicit genre pedagogy (Rothery) shows expected structure (1)' },
      { q: 'Identify four features distinguishing integration-stage writing from earlier stages.', marks: 4, markScheme: '• Range of sentence types including non-finite (1)\n• Conscious register shifts between genres/audiences (1)\n• Strong cohesion — varied connectives, pronoun reference (1)\n• Modality/evaluation/stance (1)' },
      { q: 'State two limitations of Kroll\'s stage model.', marks: 4, markScheme: '• Individual variation — children progress at different rates (1)\n• Cultural + SES factors matter (1)\n• Children can be at different stages across genres (Britton) (1)\n• Stages are descriptive tendencies not deterministic (1)' },
      { q: 'Describe Gentry\'s phonetic spelling stage with an example.', marks: 3, markScheme: '• Systematic sound-letter mapping — not yet correct (1)\n• "cum" for "come", "wot" for "what" (1)\n• Evidence of rule-learning (1)' },
      { q: 'Identify three typical features of early narrative writing.', marks: 3, markScheme: '• Coordination with "and then" (1)\n• Simple past tense with limited shift (1)\n• First-person, simple orientation (1)' },
      { q: 'Analyse a Year 2 sample: "i went to the prk and i saw a dog and i had ice cream." Identify three features.', marks: 6, markScheme: '• No capitalisation of "I" or first word (1)\n• "prk" — phonetic spelling (1)\n• Repeated "and" — Kroll consolidation (1)\n• Expressive function (Britton) (1)\n• Child writes as they speak — typical of age (1)\n• Target: introduce subordination and capitalisation (1)' },
      { q: 'Identify the genre of: "Penguins are birds. They live in cold places. They eat fish." and state the developmental level.', marks: 4, markScheme: '• Genre: report (1)\n• Third-person plural + simple present (1)\n• Simple sentences — consolidation / early differentiation (1)\n• Target: elaboration with relative clauses, causal connectors (1)' },
      { q: 'Explain why explicit genre teaching (Rothery) is especially important for equity.', marks: 5, markScheme: '• Some genres are not naturally acquired from conversation (1)\n• Children with heavy home literacy enter school already familiar (1)\n• Others face disadvantage if genres not taught explicitly (1)\n• Explicit genre pedagogy levels the playing field (1)\n• Addresses educational equity AND linguistic development (1)' },
      { q: 'Describe two ways digital communication can affect children\'s writing.', marks: 4, markScheme: '• New orthographic features — abbreviations, emoji (1)\n• Encourages audience awareness (1)\n• Research (Crystal, Tagg) shows digital does not replace standard writing in educated users (1)\n• Inequalities in digital access can widen gaps (1)' },
      { q: 'Explain two reasons why punctuation is often unstable in early writing.', marks: 4, markScheme: '• Punctuation is a written convention not reflected in speech (1)\n• Children mark prosody (pauses) rather than syntactic boundaries (1)\n• Full-stop placement depends on sentence awareness — developing (1)\n• Feedback progresses from local → global (1)' },
      { q: 'Analyse a Year 6 opening: "Darkness fell across the city, silent but for a single, flickering streetlight. Mia had been waiting." Identify three features.', marks: 6, markScheme: '• Fronted adverbial (1)\n• Complex noun phrase with multiple pre-modifiers (1)\n• Past perfect — prior narrative time (1)\n• Minor sentence fragments — crafted rhythm (1)\n• Kroll differentiation/integration stage; Britton poetic function (1)\n• Textual metafunction (Halliday) and genre of literary narrative (1)' },
      { q: 'Compare two Year 2 samples (coordination-heavy recount vs simple report) and suggest teaching priorities.', marks: 8, markScheme: '• Recount: teach subordinators, cohesive pronouns, time connectives (2 + 2)\n• Report: teach elaboration — relative clauses, adjectives, adverbials (2 + 2)' },
      { q: 'Evaluate the value of combining multiple frameworks (Kroll, Britton, Rothery, Halliday) for analysing children\'s writing. [10 marks]', marks: 10, markScheme: '• Kroll — stage view (2)\n• Britton — functional view (2)\n• Rothery — genre structure (2)\n• Halliday — ideational/interpersonal/textual integration (2)\n• Triangulation: each offers partial insight (1)\n• Top-band synthesis (1)' },
      { q: 'Discuss how Vygotsky\'s ZPD applies to teaching persuasive writing in Year 5. [10 marks]', marks: 10, markScheme: '• Baseline task (2)\n• Modelled writing (2)\n• Shared writing (2)\n• Guided writing in small groups (2)\n• Independent writing with success criteria (2)' },
      { q: 'Compose a 500-word essay plan on: "Children\'s writing development is best understood as a combination of stage, function and genre." [20 marks]', marks: 20, markScheme: 'Indicative:\n• Intro: multiple frameworks needed (2)\n• Kroll — stages (3)\n• Britton — functions (3)\n• Rothery — genres (3)\n• Halliday — metafunctions (2)\n• Critical evaluation (3)\n• Conclusion — combined view gives fullest picture (2)\n• Integration of examples (2)' },
    ],
  },

  '3.1': {
    name: 'Global English (Paper 3 pathway)',
    questions: [
      { q: 'Name Kachru\'s three circles with two examples each.', marks: 6, markScheme: '• Inner — UK, US, Australia, Canada, NZ (any 2: 2)\n• Outer — India, Nigeria, Singapore, Ghana, Kenya (any 2: 2)\n• Expanding — China, Brazil, Russia, Japan (any 2: 2)' },
      { q: 'State one limitation of Kachru\'s model.', marks: 3, markScheme: '• Reinforces Inner-Circle hierarchy (1)\n• Categories blur — Indian English is pluricentric (1)\n• Many Expanding-Circle speakers highly proficient (1)' },
      { q: 'Describe Jenkins\'s Lingua Franca Core.', marks: 4, markScheme: '• Only certain phonological features essential for ELF intelligibility (1)\n• Consonant clusters preserved; RP vowels not essential (1)\n• Shifts teaching from Inner-Circle accent targets to intelligibility (1)\n• Legitimises local norms (1)' },
      { q: 'Describe Schneider\'s Dynamic Model of post-colonial Englishes.', marks: 5, markScheme: '• Five stages: foundation, exonormative stabilisation, nativisation, endonormative stabilisation, differentiation (3)\n• Tracks evolution from imported to locally owned (1)\n• Political + linguistic drivers at each stage (1)' },
      { q: 'Describe four features of Indian English.', marks: 4, markScheme: '• "Prepone" (1)\n• Progressive with stative verbs — "I am understanding" (1)\n• Invariant tag "isn\'t it?" (1)\n• Code-switching with Hindi/local languages (1)' },
      { q: 'Describe four features of Singlish.', marks: 4, markScheme: '• Final particles "lah", "lor", "meh" (2)\n• Topic-prominent syntax influenced by Malay/Chinese (1)\n• Lexis from Malay, Hokkien, Tamil, Cantonese (1)' },
      { q: 'Describe three features of Nigerian English.', marks: 3, markScheme: '• "Go-slow" = traffic jam (1)\n• Distinctive modal use (1)\n• Loan lexis from Yoruba, Igbo, Hausa (1)' },
      { q: 'Define pidgin, creole and the lectal continuum.', marks: 4, markScheme: '• Pidgin — simplified contact language, no native speakers (1)\n• Creole — a pidgin acquired natively (1)\n• Lectal continuum — basilect → mesolect → acrolect (2)' },
      { q: 'Explain translanguaging (García) with an example.', marks: 4, markScheme: '• Multilingual speakers draw on their full repertoire flexibly (1)\n• Rejects view of languages as bounded systems (1)\n• Example: bilingual student using English in essays, Spanish in discussion (1)\n• Educational implication: pedagogy valuing all learner languages improves outcomes (1)' },
      { q: 'Discuss why the native/non-native binary is increasingly problematic in ELF.', marks: 5, markScheme: '• Most global English use is between non-native speakers (1)\n• Many ELF speakers are highly proficient (1)\n• "Native" confers unwarranted authority (Jenkins) (1)\n• "Expert user" is preferred (1)\n• Widdowson: ownership of English is shared globally (1)' },
      { q: 'Describe Crystal\'s concept of "new Englishes".', marks: 4, markScheme: '• English\'s global spread has produced multiple pluricentric varieties (1)\n• Each with legitimate norms (1)\n• The idea of a single "correct" English is incompatible with 2-3 billion speakers (1)\n• Broadly descriptivist, anti-hierarchy position (1)' },
      { q: 'Identify three factors contributing to ethnolinguistic vitality (Giles).', marks: 3, markScheme: '• Demographic strength (1)\n• Institutional support (1)\n• Status / prestige (1)' },
      { q: 'Define code-switching and code-mixing with an example of each.', marks: 4, markScheme: '• Code-switching — alternation across clauses/turns (2)\n• Code-mixing — mixing elements within a clause (2)' },
      { q: 'Analyse how media representations of Outer-Circle Englishes in British press construct ideology.', marks: 6, markScheme: '• Often exoticised or belittled (1)\n• Reflects colonial attitudes (1)\n• Linguistic features framed as error (1)\n• Cheshire, Crystal: representations lag behind linguistic reality (1)\n• Ideology enacted through lexical and grammatical choices (1)\n• Worth contrasting with pluricentric position of Crystal, Jenkins (1)' },
      { q: 'Explain why English\'s global spread is not politically neutral.', marks: 5, markScheme: '• Reflects colonial history (1)\n• Economic/cultural hegemony (1)\n• Educational policy choices shape access (1)\n• Local speakers shape English through nativisation (1)\n• Translanguaging reclaims multilingual practice (1)' },
      { q: 'Describe how a Philippine English or Hong Kong English speaker might show pluricentric features.', marks: 6, markScheme: '• Local lexis (comfort room; cha chaan teng) (2)\n• Code-switching with Tagalog / Cantonese (2)\n• Distinctive phonology (vowel mergers, stress patterns) (2)' },
      { q: 'Explain Cheshire &amp; Kerswill\'s view of MLE.', marks: 4, markScheme: '• MLE emerged from dense multiethnic peer networks in inner London (1)\n• Features shared across ethnic lines (1)\n• A community-of-practice variety, not tied to one ethnicity (1)\n• Spreading beyond London as a youth variety (1)' },
      { q: 'Evaluate: "English\'s global spread threatens linguistic diversity." [15 marks]', marks: 15, markScheme: '• Pro (endangerment): English\'s role has contributed to language death in some contexts (3)\n• Pro: educational pressures favour English (2)\n• Con: colonisation, policy and economics do more than English itself (3)\n• Con: local adaptation and hybridisation show local agency (3)\n• Crystal: English pluralises; many "new Englishes" (2)\n• Balanced evaluation (2)' },
      { q: 'Analyse an invented extract with features of Indian English. Integrate at least two theorists. [12 marks]', marks: 12, markScheme: '• Identify features — lexis, grammar, phonology (3)\n• Social context (3)\n• Theorist 1: Kachru (pluricentric) (2)\n• Theorist 2: García (translanguaging) / Jenkins (ELF) (2)\n• Evaluation (2)' },
      { q: 'Write a 600-word essay plan: "English is becoming a cluster of world Englishes rather than a single language." [20 marks]', marks: 20, markScheme: 'Indicative:\n• Intro: pluricentric hypothesis (2)\n• Kachru\'s circles + critique (3)\n• Jenkins ELF + LFC (3)\n• Crystal\'s new Englishes (3)\n• Example 1 (Indian English) (3)\n• Example 2 (Singlish) (3)\n• Evaluation (2)\n• Conclusion: pluricentric consensus (2)' },
    ],
  },

  '3.2': {
    name: 'Language and Gender Identity (Paper 3 pathway)',
    questions: [
      { q: 'State three features Lakoff (1975) proposed as "women\'s language".', marks: 3, markScheme: '• Hedges (1)\n• Tag questions (1)\n• Empty adjectives, rising intonation, polite forms — any (1)' },
      { q: 'Distinguish deficit, dominance and difference models.', marks: 3, markScheme: '• Deficit (Lakoff) (1)\n• Dominance (Zimmerman &amp; West; Fishman) (1)\n• Difference (Tannen) (1)' },
      { q: 'Describe Zimmerman &amp; West (1975) and their finding.', marks: 3, markScheme: '• Analysed mixed/same-sex conversations (1)\n• Men accounted for ~96% of interruptions in mixed dyads (1)\n• Argued for male conversational dominance (1)' },
      { q: 'Describe Fishman\'s "conversational shitwork" argument.', marks: 4, markScheme: '• Women ask nearly 3× as many questions (1)\n• Use minimal responses to sustain topics (1)\n• Do interactional labour that men benefit from (1)\n• Gendered labour within interaction (1)' },
      { q: 'Explain Tannen\'s "difference" model and two contrasts.', marks: 4, markScheme: '• Men/women socialised into different communicative subcultures (1)\n• Men: report talk (status, information) (1)\n• Women: rapport talk (connection, empathy) (1)\n• Other pairs: advice/understanding, conflict/compromise (1)' },
      { q: 'Describe Cameron (2007).', marks: 4, markScheme: '• Gender differences overstated (1)\n• Meta-analyses show large overlap (1)\n• Critiques popular "Mars and Venus" narrative (1)\n• Gender reflects context, power and community of practice (1)' },
      { q: 'Explain Butler\'s "performativity" and its implication for language.', marks: 4, markScheme: '• Gender constituted through repeated acts (1)\n• Language is one such act (1)\n• There is no "essential" male/female voice (1)\n• Opens space for non-binary analysis (1)' },
      { q: 'Describe O\'Barr &amp; Atkins\' critique of Lakoff.', marks: 4, markScheme: '• Courtroom witnesses study (1)\n• Features correlate with POWER not gender (1)\n• Renamed "powerless language" (1)\n• Shows deficit model confounds gender with power (1)' },
      { q: 'Describe Holmes\' (1992) argument about tag questions.', marks: 4, markScheme: '• Multiple functions: epistemic, facilitative, softening, challenging (1 + 1)\n• Women use facilitative tags more than men (1)\n• About managing interaction, not weakness (1)' },
      { q: 'Identify three ways lexis historically encodes gender inequality.', marks: 6, markScheme: '• Lexical asymmetry (master/mistress) (1 + 1)\n• Generic masculine (chairman) (1 + 1)\n• Marked female forms (female doctor) (1 + 1)' },
      { q: 'Analyse a hypothetical manager/employee exchange for gender and power.', marks: 8, markScheme: '• Identify directness/indirectness (1)\n• Identify hedges/rising intonation (1)\n• Apply Lakoff (deficit reading) (1)\n• Apply dominance model (1)\n• Apply Cameron critique (1)\n• Apply Butler — performance of gender (1)\n• Apply Brown &amp; Levinson — face-saving (1)\n• Integrate power + role + gender (1)' },
      { q: 'Define community of practice (Eckert &amp; McConnell-Ginet) and one benefit.', marks: 4, markScheme: '• Group cohering around shared practices (1)\n• Members share repertoires (1)\n• Benefit: allows intersectional analysis (1)\n• Supports context-sensitive approaches (1)' },
      { q: 'Describe Dale Spender\'s argument in "Man Made Language" (1980).', marks: 4, markScheme: '• English shaped historically by men encodes male power (1)\n• Examples: generic masculine, lexical asymmetries (1)\n• Women "silenced" by male-dominant language (strong claim) (1)\n• Strong form critiqued; observation widely accepted (1)' },
      { q: 'Analyse how a tabloid might represent a female politician differently from a male counterpart.', marks: 6, markScheme: '• Evaluative adjectives ("shrill") disproportionately (1 + 1)\n• Focus on appearance vs policy (1 + 1)\n• First-name use vs title (1 + 1)' },
      { q: 'Identify three criticisms of older gender/language studies.', marks: 3, markScheme: '• WEIRD samples (1)\n• Implicit heteronormativity (1)\n• Essentialist binaries ignoring intersectionality (1)' },
      { q: 'Explain the genderlect metaphor and one critique.', marks: 3, markScheme: '• Tannen treats men/women as distinct dialects (1)\n• Critique: ignores huge within-gender variation (1)\n• Risks essentialism (1)' },
      { q: 'Discuss: "Gender differences in language are performed within specific contexts." [15 marks]', marks: 15, markScheme: '• Lakoff/deficit — foundational but over-general (2)\n• Zimmerman &amp; West/dominance — context-specific (2)\n• Tannen/difference — influential but essentialist (2)\n• Cameron — small differences, large overlap (2)\n• Butler — performativity (2)\n• Eckert — community of practice (2)\n• Conclusion: context-driven performance (3)' },
      { q: 'Analyse how advertising constructs gendered consumers. Use two examples. [10 marks]', marks: 10, markScheme: '• Razor advert: Latinate "precision", military metaphors, imperatives (3)\n• Perfume advert: evaluative "empty" adjectives, emotive abstraction, sensual imagery (3)\n• Graphology: colour palettes, font weight (2)\n• Butler on performativity; Goffman on gender display (2)' },
      { q: 'Evaluate the usefulness of Lakoff\'s work today. [10 marks]', marks: 10, markScheme: '• Historical value — agenda-setting (2)\n• Features identified are real (2)\n• Limitations: introspection, deficit framing, power confused with gender (3)\n• Still useful via Holmes (multi-function) and O\'Barr &amp; Atkins (power) (2)\n• Lakoff as starting point, not destination (1)' },
      { q: 'Write a 20-mark commentary on how texts perform gender through linguistic choices, integrating three theorists.', marks: 20, markScheme: 'Up to 20:\n• Butler — performativity (3)\n• Lakoff / O\'Barr &amp; Atkins (3)\n• Cameron — critique of essentialism (3)\n• Eckert — community of practice (3)\n• Example analysed (4)\n• Evaluation (2)\n• Conclusion (2)' },
    ],
  },

  '3.3': {
    name: 'Language of Journalism (Paper 3 pathway)',
    questions: [
      { q: 'Distinguish "tabloid" and "broadsheet" with two features of each.', marks: 4, markScheme: '• Tabloid: smaller format, popular audience; short emotive headlines, Anglo-Saxon lexis (2)\n• Broadsheet: larger format, educated audience; balanced syntax, Latinate lexis, detailed quotation (2)' },
      { q: 'State six of Galtung &amp; Ruge\'s news values.', marks: 6, markScheme: '• Frequency / recency (1)\n• Negativity (1)\n• Elitism (1)\n• Meaningfulness (1)\n• Unambiguity (1)\n• Consonance / personalisation / continuity / threshold (any valid) (1)' },
      { q: 'Explain the "inverted pyramid" structure.', marks: 3, markScheme: '• Most important info first (1)\n• Progressively less important (1)\n• Allows readers to stop at any point (1)' },
      { q: 'Describe four features of effective tabloid headlines.', marks: 4, markScheme: '• Puns / alliteration (1)\n• Monosyllabic Anglo-Saxon lexis (1)\n• Caps / red banner (1)\n• Minor sentence / fragment for impact (1)' },
      { q: 'Describe four features of a broadsheet editorial.', marks: 4, markScheme: '• Balanced syntax (1)\n• Latinate lexis (1)\n• Institutional "we" (1)\n• Careful attribution and quotation (1)' },
      { q: 'Describe four features of a news-website front page that differ from print.', marks: 4, markScheme: '• Hyperlinks (1)\n• Multiple updated stories (1)\n• Video embeds (1)\n• Comment threads / interactivity (1)' },
      { q: 'Explain Fairclough\'s "synthetic personalisation" with a journalism example.', marks: 4, markScheme: '• Intimate/inclusive language simulating personal relationship with mass audience (1)\n• Example: "WE all want safer streets" — inclusive "we" (1)\n• Manufactures intimacy (1)\n• Often used in columns / charity appeals (1)' },
      { q: 'Analyse how active/passive choice shapes representation in news.', marks: 4, markScheme: '• Active foregrounds agent: "Police shot protester" (1)\n• Passive demotes agent: "Protester was shot" (1)\n• Agent-less passive: "Shots were fired" — agency erased (1)\n• Grammar encodes blame / responsibility distribution (1)' },
      { q: 'Explain three types of presupposition in news headlines.', marks: 3, markScheme: '• Definite article "the Y" presupposes existence (1)\n• Factive verbs — "reveals" presupposes truth (1)\n• Possessive / relative clauses embed assumption (1)' },
      { q: 'Identify three features of a longform / literary journalism piece.', marks: 3, markScheme: '• Narrative voice + sensory detail (1)\n• Character-led opening (1)\n• Mix of scene, dialogue, reflection (1)' },
      { q: 'Analyse a tabloid headline: "MIGRANT TIDE: Britain under siege". Identify at least four features.', marks: 8, markScheme: '• Semantic field of natural disaster / warfare (1 + 1)\n• Capitalisation, graphological foregrounding (1)\n• Minor sentence / fragment (1)\n• Passive "under siege" positioning Britain as victim (1)\n• Presupposes migration = attack — ideological representation (1)\n• Alternative lexical choices would produce different representation (1)\n• Fairclough CDA relevant (1)' },
      { q: 'Describe the structure of a standard news story.', marks: 4, markScheme: '• Headline (1)\n• Byline + dateline (1)\n• Lead paragraph with who/what/when/where (1)\n• Detail + quotations + background in decreasing importance (1)' },
      { q: 'Explain three lexical features of "tabloidese".', marks: 3, markScheme: '• Short action verbs — "slam", "axe", "spark" (1)\n• Adjective-noun compressions — "sex-scandal MP" (1)\n• Informal / colloquial register (1)' },
      { q: 'Discuss three features of online clickbait headlines.', marks: 3, markScheme: '• Curiosity gap — "You won\'t believe what happened next" (1)\n• Question formats (1)\n• Emotive / sensational hooks (1)' },
      { q: 'Compare a broadsheet headline and a tabloid headline on the same event.', marks: 6, markScheme: '• Tabloid: emotive, short, puns, capitalised (1 + 1)\n• Broadsheet: balanced, neutral, Latinate (1 + 1)\n• Representation of same event constructed differently (1)\n• Ideology encoded via lexical and grammatical choice (1)' },
      { q: 'Evaluate: "News is a neutral reflection of reality." [15 marks]', marks: 15, markScheme: '• Selection (news values) is not neutral (3)\n• Lexical choice encodes stance (3)\n• Grammar (active/passive/nominalisation) redistributes agency (3)\n• Graphology frames meaning (2)\n• Fairclough CDA — discourse is social practice (2)\n• Conclusion: news is never neutral; the best can be transparent (2)' },
      { q: 'Analyse how a charity appeal constructs emotional engagement. Use two features.', marks: 6, markScheme: '• Direct address / imperative (1 + 1)\n• Personal anecdote + sensory lexis (1 + 1)\n• Synthetic personalisation; inclusive "we" (1 + 1)' },
      { q: 'Write a 20-mark commentary on the language of online political news. Use at least three theorists.', marks: 20, markScheme: 'Up to 20:\n• Galtung &amp; Ruge on news values (3)\n• Fairclough on CDA + synthetic personalisation (3)\n• Halliday metafunctions (3)\n• Example analysed (4)\n• Multimodal + comment-thread features (3)\n• Ideological evaluation (2)\n• Conclusion (2)' },
      { q: 'Compare broadsheet and tabloid coverage of a single event. [15 marks]', marks: 15, markScheme: '• Choose concrete example (2)\n• Lexis comparison (3)\n• Grammar comparison (3)\n• Graphology comparison (3)\n• Representation of event/group (2)\n• Conclusion: neither is "objective"; each constructs the event through choices (2)' },
      { q: 'Analyse how photography and caption combine to frame a news story. [10 marks]', marks: 10, markScheme: '• Image selection (3)\n• Cropping and composition (3)\n• Caption lexis (2)\n• Multimodal interaction — anchorage vs relay (2)' },
    ],
  },

  '3.4': {
    name: 'Language and Power (Paper 3 pathway)',
    questions: [
      { q: 'Distinguish instrumental and influential power with an example of each.', marks: 4, markScheme: '• Instrumental — institutional authority (law, government) (1)\n• Example: court summons (1)\n• Influential — persuasion via media, advertising, rhetoric (1)\n• Example: political speech, advert (1)' },
      { q: 'Define synthetic personalisation (Fairclough).', marks: 3, markScheme: '• Use of intimate/inclusive language to simulate personal relationship with mass audience (1)\n• Example: supermarket email "Hi Tom, we\'ve saved your favourites" (1)\n• Manufactures intimacy at scale (1)' },
      { q: 'State Brown &amp; Levinson\'s two aspects of face and give one politeness strategy for each.', marks: 4, markScheme: '• Positive face — desire to be liked (1); strategy: compliments, inclusive "we" (1)\n• Negative face — desire not to be imposed on (1); strategy: hedges, indirect requests, apologies (1)' },
      { q: 'Describe the Sinclair &amp; Coulthard IRF model and what it reveals.', marks: 4, markScheme: '• Teacher Initiation → pupil Response → teacher Feedback (1 + 1)\n• Teacher controls two of three turns (1)\n• Grammatical structure enacts institutional power (1)' },
      { q: 'Identify four features of "powerful" speech.', marks: 4, markScheme: '• Imperatives (1)\n• Modals of obligation — must, should (1)\n• Directives (1)\n• Absence of hedging; declarative certainty (1)' },
      { q: 'Identify four features of "powerless" speech.', marks: 4, markScheme: '• Hedges (1)\n• Tag questions (1)\n• Rising intonation on declaratives (1)\n• Polite forms, apologies (1)' },
      { q: 'Explain how passive and nominalisation in "Mistakes were made" work as power moves.', marks: 4, markScheme: '• Passive — removes agent (1)\n• Nominalisation — turns process into abstract thing (1)\n• Responsibility acknowledged but agent concealed (1)\n• Grammar is ideological, not merely stylistic (1)' },
      { q: 'Describe four features of legal register and explain how they enact instrumental power.', marks: 6, markScheme: '• Archaic Latinate lexis ("herewith", "forthwith") (1 + 1)\n• Formal passives (1 + 1)\n• Embedded clauses for precision (1)\n• Gatekeeping register restricts lay access (1)' },
      { q: 'Describe Fairclough\'s three-dimensional model of discourse.', marks: 3, markScheme: '• Text — the specific linguistic choices (1)\n• Discursive practice — production and reception (1)\n• Social practice — ideological and institutional context (1)' },
      { q: 'Explain three features of advertising that construct influential power.', marks: 3, markScheme: '• Emotive lexis + rhetorical questions (1)\n• Imperative call to action (1)\n• Inclusive "we" and synthetic personalisation (1)' },
      { q: 'Analyse an invented political speech extract for three power features.', marks: 6, markScheme: '• Triadic structure for rhythmic authority (1)\n• Inclusive "we" + modal obligation "we must" (1 + 1)\n• Fronted adverbial building rhetorical peak (1)\n• Rhetorical questions to engage audience (1)\n• Ties to Fairclough\'s influential power (1)' },
      { q: 'Describe three features of courtroom language that enact power.', marks: 3, markScheme: '• Turn-taking controlled by judge (1)\n• Formal archaic lexis (1)\n• Declarative questions with presupposition (1)' },
      { q: 'Explain how silence and interruption function as power in discourse.', marks: 4, markScheme: '• Silence can refuse to respond or be denied the floor (1 + 1)\n• Interruption asserts dominance by the interrupter (1)\n• Context determines meaning — supportive overlap vs intrusive interruption (1)' },
      { q: 'Discuss three features of doctor-patient interactions that typically show asymmetrical power.', marks: 3, markScheme: '• Doctor leads question-answer sequences (1)\n• Jargon gatekeeping (1)\n• Interruption and topic control by doctor (1)' },
      { q: 'Describe van Dijk\'s approach to discourse and power.', marks: 4, markScheme: '• Discourse reproduces ideology through everyday choices (1)\n• Focus on elite discourses (politics, media) (1)\n• Analyses lexical/grammatical/pragmatic encoding of power (1)\n• Extends CDA to social cognition (1)' },
      { q: 'Evaluate: "Powerful language is always formal and Latinate." [15 marks]', marks: 15, markScheme: '• Legal/governmental texts use formal Latinate (instrumental power) (3)\n• But power also enacted through informality (synthetic personalisation) (3)\n• Silence, gatekeeping, interruption (3)\n• Form alone does not determine power — context matters (2)\n• Fairclough CDA (2)\n• Conclusion: the claim oversimplifies (2)' },
      { q: 'Discuss how advertising reproduces power asymmetry between brand and consumer. [10 marks]', marks: 10, markScheme: '• Synthetic personalisation (2)\n• Imperative call to action (2)\n• Emotive evaluative lexis (2)\n• Inclusive "we" + manufactured intimacy (2)\n• Reflective critique — the friendly tone masks asymmetry (2)' },
      { q: 'Analyse a legal document extract for features of instrumental power. [12 marks]', marks: 12, markScheme: '• Archaic Latinate lexis (2)\n• Formal passives (2)\n• Embedded clauses + precision (2)\n• Gatekeeping register (2)\n• Absence of hedging; declarative certainty (2)\n• Institutional voice (1)\n• Power enacted through register (1)' },
      { q: 'Analyse a politician\'s speech for four power features. [12 marks]', marks: 12, markScheme: '• Modality — obligation (3)\n• Inclusive "we" (3)\n• Triadic structures (2)\n• Rhetorical questions (2)\n• Synthesis with Fairclough (2)' },
      { q: 'Write a 600-word essay plan on: "All language involves power relations." [20 marks]', marks: 20, markScheme: 'Indicative:\n• Intro: CDA claim (2)\n• Fairclough framework (3)\n• Brown &amp; Levinson face (3)\n• Sinclair &amp; Coulthard IRF (3)\n• Examples from media, classroom, workplace, courtroom (4)\n• Counter-arguments and responses (3)\n• Conclusion (2)' },
    ],
  },

  '3.5': {
    name: 'Language and Regional Variation (Paper 3 pathway)',
    questions: [
      { q: 'Define "dialect" and "accent" with a one-sentence example of each.', marks: 2, markScheme: '• Dialect — variety with distinctive lexis + grammar (e.g. Geordie) (1)\n• Accent — pronunciation patterns (e.g. Cockney) (1)' },
      { q: 'Describe Labov\'s New York department store study and main finding.', marks: 5, markScheme: '• "Where is the fourth floor?" elicited in three stores (1)\n• /r/ increased with prestige and formality (1)\n• Lower-middle-class Macy\'s hypercorrected (1)\n• Established variable-social correlation (1)\n• Introduced sociolinguistic interview technique (1)' },
      { q: 'Describe Trudgill\'s Norwich study and three findings.', marks: 6, markScheme: '• Studied 5 social classes on variables including -ing (1)\n• Standard forms increased with class and formality (1)\n• Women > men of same class used standard forms (1)\n• Men over-reported non-standard use (1)\n• Women over-reported standard use (1)\n• Conclusion: class + gender + attitudes all matter (1)' },
      { q: 'Describe Milroy\'s Belfast study and explain network strength.', marks: 5, markScheme: '• Network strength = density + multiplexity (1)\n• High-density networks enforce local norms (1)\n• Belfast: dense networks correlated with vernacular maintenance (1)\n• Looser networks (often women) showed more standard forms (1)\n• Shifted field from class to network (1)' },
      { q: 'Describe Giles\'s Accommodation Theory with two examples.', marks: 5, markScheme: '• Speakers adjust style in interaction (1)\n• Convergence — rapport-building (1)\n• Divergence — identity assertion (1)\n• Example: British migrant to Australia converging (1)\n• Example: teenager thickening local accent with parents (1)' },
      { q: 'Identify four factors correlating with UK language variation.', marks: 4, markScheme: '• Class (1)\n• Age (1)\n• Gender (1)\n• Region, network, ethnicity — any valid fourth (1)' },
      { q: 'Identify four features of Cockney.', marks: 4, markScheme: '• H-dropping (1)\n• T-glottalisation (1)\n• Th-fronting (1)\n• Double negation; rhyming slang (1)' },
      { q: 'Define overt and covert prestige and explain why both matter.', marks: 4, markScheme: '• Overt — publicly valued standard forms (1)\n• Covert — hidden prestige within peer groups (1)\n• Both act on every speaker (1)\n• Ignoring either gives partial picture (1)' },
      { q: 'Explain dialect levelling and name a researcher.', marks: 4, markScheme: '• Reduction of distinctive local features (1)\n• Caused by mobility, media, education (1)\n• Paul Kerswill (Milton Keynes) (1)\n• New varieties (MLE) emerge alongside levelling (1)' },
      { q: 'Analyse a West-London builder\'s speech for identity markers.', marks: 8, markScheme: '• Non-standard preterite "we was" (1)\n• "Me" as possessive (1)\n• "Ain\'t" — covert prestige (1)\n• Discourse marker "yeah nah" (1)\n• Address "mate", "bruv" (1)\n• Working-class London identity marked through speech (1)\n• Apply Trudgill (covert prestige) + Milroy (network) (1)\n• Avoid deficit framing (1)' },
      { q: 'Explain three occupation-linked register features you might find.', marks: 3, markScheme: '• Specialist jargon (1)\n• Field-specific genres (SOAP notes, legal briefs) (1)\n• Acronyms / in-group lexis (1)' },
      { q: 'Describe Bernstein\'s restricted/elaborated codes and one critique.', marks: 5, markScheme: '• Restricted code — context-bound, shared-assumption (1)\n• Elaborated code — explicit, decontextualised (1)\n• Bernstein: schools reward elaborated (1)\n• Critique: Labov\'s AAVE research shows vernacular is rule-governed (1)\n• Modern preference: "code difference" not "code deficit" (1)' },
      { q: 'Describe K.M. Petyt\'s Bradford study.', marks: 4, markScheme: '• H-dropping in Bradford (1)\n• Correlation with social class (1)\n• More H-dropping in lower classes (1)\n• Confirmed class-based patterning of UK phonology (1)' },
      { q: 'Describe Cheshire\'s Reading study of adolescents.', marks: 4, markScheme: '• Adolescent peer groups in Reading (1)\n• Non-standard grammar correlated with peer-group toughness (1)\n• Covert prestige within youth cultures (1)\n• Identity drives variation — not class alone (1)' },
      { q: 'Define community of practice (Eckert &amp; McConnell-Ginet).', marks: 4, markScheme: '• A group cohering around shared practices and goals (1)\n• Members develop shared repertoires including linguistic (1)\n• Allows intersectional analysis (class, gender, ethnicity, age) (1)\n• Captures fluid, constructed identity (1)' },
      { q: 'Explain pidgin, creole, and the lectal continuum.', marks: 4, markScheme: '• Pidgin — simplified contact language, no native speakers (1)\n• Creole — pidgin acquired natively, expanded grammar (1)\n• Lectal continuum — basilect → acrolect (1)\n• Decreolisation moves varieties towards acrolect (1)' },
      { q: 'Discuss: "Social class remains the most important variable in UK sociolinguistics." [15 marks]', marks: 15, markScheme: '• Historically central (Labov, Trudgill, Petyt) (3)\n• Cannot explain gender/age patterns or covert prestige alone (3)\n• Milroy: network density outperforms class in some cases (3)\n• Eckert: community of practice challenges static categories (2)\n• MLE shows ethnicity interacts with age and class (2)\n• Conclusion: class is one variable among several (2)' },
      { q: 'Analyse a distinctive speech feature of your own regional area with two theorists. [15 marks]', marks: 15, markScheme: '• Identify a specific feature (2)\n• Describe phonetic realisation (2)\n• Link to social variables (3)\n• Theorist 1: Labov/Trudgill (3)\n• Theorist 2: Milroy / Kerswill (3)\n• Evaluation: identity, covert prestige, media (2)' },
      { q: 'Discuss the role of media in dialect levelling. [10 marks]', marks: 10, markScheme: '• Media spreads forms across regions (2)\n• Kerswill: mobility + media reduce distinctive local features (2)\n• BUT local identity and network density resist full levelling (2)\n• New varieties emerge via media + migration (MLE) (2)\n• Balanced evaluation (2)' },
      { q: 'Write a 20-mark commentary on how UK dialects are changing in the 21st century.', marks: 20, markScheme: 'Up to 20:\n• Intro: dynamic UK dialect landscape (2)\n• Labov + Trudgill + Milroy foundations (3)\n• Kerswill on levelling + MLE (3)\n• Identity-driven variation (3)\n• Covert prestige (3)\n• Digital media influence (3)\n• Evaluation and conclusion (3)' },
    ],
  },

};
